-- =============================================================================
-- BUILD QUALITY (Q-FACTOR) INSERTS
-- =============================================================================

-- car_id=13 | BMW M340i xDrive G20 | B58 3.0T 382hp
-- Q: 82*0.25 + 78*0.10 + 78*0.20 + 78*0.15 + 68*0.15 + 70*0.15 = 76.3
INSERT INTO build_quality (id, car_id, q_score, score_body_construction, score_nvh_isolation, score_interior_materials, score_paint_corrosion, score_electrical_aging, score_cosmetic_aging, body_construction_notes, nvh_isolation_notes, interior_materials_notes, paint_corrosion_notes, electrical_aging_notes, cosmetic_aging_notes, q_score_notes, platform_type, assembly_plant, weld_technology, panel_gap_mm, engine_mount_type, glass_type, leather_grade, wood_type, paint_stages, sound_deadening_rating, source) VALUES (59, 13, 76.3, 82, 78, 78, 78, 68, 70, 'CLAR platform shared with G30 5 Series. Mixed high-strength steel and aluminum construction — aluminum hood, front fenders. Hot-stamped B-pillar and roof rail. Multi-link front and rear. Panel gaps 4-4.5mm (good for segment). Production maturity from several years of CLAR production. G20 benefits from continuous refinements.', 'Good NVH for sport sedan. Hydraulic engine mounts standard on M340i. B58TU inherently smooth I6. Acoustic laminated windshield standard. ZF 8HP well-isolated. Run-flat tire harshness present but BMW updated tire specs. M Sport suspension option with adaptive dampers better in Comfort mode. Cabin quietness competitive for class but not 5 Series-level.', 'M Sport standard with Vernasca leather — softer and better grain than Dakota. Sensatec on non-M Sport. iDrive 7.0 with 10.25-inch screen. Brushed aluminum trim, optional open-pore wood. Good fit and finish. Less piano black than pre-LCI G30. Optional heads-up display. Stitching quality above average. Cooled seats available.', 'Modern BMW paint process. Multi-stage cathodic dip primer, base coat, clear coat. No systemic paint issues reported. Standard colors consistent. Individual paint options have more clear coat depth. Aluminum panels don''t rust but cosmetic corrosion risk on chips. Paint hardness average for German cars.', 'iDrive 7 more stable than earlier versions. B58TU addresses many B58 issues: improved water pump, better thermostat, updated PCV. 48V mild hybrid on some models adds complexity. Digital Key and OTA updates add software complexity. Too early for definitive long-term aging data but trajectory positive.', 'Vernasca leather should age well — positive initial reports at 30-50K miles. Less piano black means fewer visible scratches. Updated door card materials more durable. BMW steering wheel gloss pattern at 60K+. Dashboard materials holding up. Good 3-year lease return condition.', 'M340i G20 Q-score 76.3. B58TU + CLAR platform = solid modern BMW. Good body construction, competitive NVH, nice interior. Better than E90 in every Q dimension. Not at 5 Series level on NVH or interior but close. Strong daily driver build quality.', 'shared', 'San Luis Potosi (Mexico) / Munich (Germany)', 'mixed', 4.2, 'hydraulic', 'acoustic_laminated', 'standard', 'real_wood', 4, 'above_average', 'sample');

-- car_id=19 | BMW M3 CSL E46 | S54 3.2L NA 355hp
-- Q: 68*0.25 + 35*0.10 + 60*0.20 + 55*0.15 + 45*0.15 + 48*0.15 = 54.7
INSERT INTO build_quality (id, car_id, q_score, score_body_construction, score_nvh_isolation, score_interior_materials, score_paint_corrosion, score_electrical_aging, score_cosmetic_aging, body_construction_notes, nvh_isolation_notes, interior_materials_notes, paint_corrosion_notes, electrical_aging_notes, cosmetic_aging_notes, q_score_notes, platform_type, assembly_plant, weld_technology, panel_gap_mm, engine_mount_type, glass_type, leather_grade, wood_type, paint_stages, sound_deadening_rating, source) VALUES (60, 19, 54.7, 68, 35, 60, 55, 45, 48, 'E46 platform with CSL-specific lightweighting: carbon fiber roof panel, thinner rear glass, lightweight body panels. Rear subframe mounting points crack (well-documented TSB). High-quality steel for era. CSL specific: removed sound deadening, reduced insulation. Panel gaps 5-6mm. Carbon fiber roof well-bonded. Now 20+ years old, fatigue and rust on structural components.', 'CSL = purposefully stripped out for weight. Minimal sound deadening removed from factory. Thin rear glass. Single-mass flywheel transmits vibration. S54 mechanically noisy at all RPM. No acoustic glass. No active noise cancellation. Road noise with 19-inch staggered setup significant. Exhaust always present in cabin. At 80mph you hear everything — by design. This is a track-bred car.', 'CSL-specific: carbon fiber bucket seats (not standard M3 sport seats). Alcantara steering wheel and handbrake. Stripped interior — no rear seats in some markets. Door panels minimal. Lightweight construction throughout. Materials quality good for era but spartan. Carbon fiber trim extensive. Function over form philosophy.', 'BMW paint 2000-2006 average. Clear coat failure on horizontal surfaces at 15+ years. Carbon black and jet black susceptible. Stone chips on front expose steel. Rear quarter panel rust near wheel arch common on northern cars. Paint thin by modern standards (~100 microns). CSL specific: some unique colors (Silverstone Metallic, Fire Orange).', 'E46 electronics aging poorly. VANOS solenoids fail. SMG-II hydraulic pump electronics fail. Camshaft position sensors regular failure. Window regulators fail (cable design flaw). Instrument cluster pixel death. HK amplifier failure. SMG-specific: hydraulic control unit electronics degrade. CSL gauge cluster unique and expensive.', 'CSL-specific lightweight materials wear like a race car. Carbon fiber seats can develop stress marks. Alcantara steering wheel wears faster than leather. Exposed carbon fiber can yellow/crack in UV. Minimal interior means what''s there takes more abuse. Dashboard material okay. Headliner sag common. Overall: patina is part of the CSL character.', 'E46 M3 CSL Q-score 54.7. Purpose-built track car with road registration. Low NVH is by design, not defect. Subframe cracking is the real structural concern. SMG electronics aging poorly. Interior is spartan by choice. Scores reflect 20+ year old lightweight special — built for purpose not luxury.', 'bespoke', 'Regensburg (Germany)', 'laser_welded', 5.5, 'solid_rubber', 'standard', 'alcantara', 'carbon_fiber', 3, 'minimal', 'sample');

-- car_id=23 | BMW 740i G11 | B58 3.0T 320hp
-- Q: 86*0.25 + 88*0.10 + 85*0.20 + 80*0.15 + 58*0.15 + 72*0.15 = 78.8
INSERT INTO build_quality (id, car_id, q_score, score_body_construction, score_nvh_isolation, score_interior_materials, score_paint_corrosion, score_electrical_aging, score_cosmetic_aging, body_construction_notes, nvh_isolation_notes, interior_materials_notes, paint_corrosion_notes, electrical_aging_notes, cosmetic_aging_notes, q_score_notes, platform_type, assembly_plant, weld_technology, panel_gap_mm, engine_mount_type, glass_type, leather_grade, wood_type, paint_stages, sound_deadening_rating, source) VALUES (61, 23, 78.8, 86, 88, 85, 80, 58, 72, 'CLAR flagship platform. Mixed high-strength steel, aluminum, and carbon fiber (CFRP) in core structure. Carbon core pillar technology from 7 Series. Aluminum hood, doors, front fenders, roof. Hot-stamped B-pillar and structural members. Panel gaps 3.5-4mm (best in BMW lineup). Excellent crash structure. Body rigidity outstanding for size and weight.', 'Flagship NVH — BMW''s best at time of production. Hydraulic engine mounts standard. Acoustic laminated windshield and side glass standard. Extensive firewall insulation. B58 inherently smooth I6, very quiet at cruise. ZF 8HP well-isolated. Underbody aero panels reduce wind noise. Air suspension isolates road imperfections. Near S-Class quiet at highway speeds.', 'Nappa leather standard, optional Merino individual leather. Real wood trim — open-pore oak, poplar, fineline. Aluminum trim options. iDrive 6/7 with gesture control. Excellent fit and finish. Soft-close doors standard. Ambient lighting extensive. Optional Bowers and Wilkins audio outstanding. Rear seat executive lounge option. Above average for class.', 'BMW premium paint process on 7 Series. Extra paint stages for Individual colors. Multi-layer clear coat. Consistent panel-to-panel color match. No systemic issues reported. Aluminum panels don''t rust. Steel structural components well-protected by cathodic dip. Paint depth above average for BMW.', 'Complex luxury electronics are the concern. Multiple control modules. Air suspension management. Gesture control cameras. iDrive infotainment. Driver assistance suite. Individual electronics can fail — door modules, seat modules, K-CAN bus issues. Battery management critical. Many early G11 recalls for software-related issues.', 'Nappa leather ages well — develops patina rather than cracking at 80-100K. Real wood trim holds up. Aluminum trim can show fingerprints and light scratches. Piano black surfaces scratch easily (less in 7 Series than 3/5 Series). Headliner holds up. Dashboard materials premium quality. Overall ages like a well-maintained luxury car.', '740i G11 Q-score 78.8. BMW flagship build quality benefits from carbon core construction and premium materials. Best panel gaps in BMW lineup. Excellent NVH. Electronics complexity is the aging concern. B58 I6 much better reliability path than N63 V8 750i.', 'shared', 'Dingolfing (Germany)', 'mixed', 3.8, 'hydraulic', 'acoustic_laminated', 'nappa', 'real_wood', 5, 'excellent', 'sample');

-- car_id=37 | BMW 3 Series E90 | N52 3.0L NA 255hp
-- Q: 72*0.25 + 70*0.10 + 62*0.20 + 65*0.15 + 58*0.15 + 60*0.15 = 64.8
INSERT INTO build_quality (id, car_id, q_score, score_body_construction, score_nvh_isolation, score_interior_materials, score_paint_corrosion, score_electrical_aging, score_cosmetic_aging, body_construction_notes, nvh_isolation_notes, interior_materials_notes, paint_corrosion_notes, electrical_aging_notes, cosmetic_aging_notes, q_score_notes, platform_type, assembly_plant, weld_technology, panel_gap_mm, engine_mount_type, glass_type, leather_grade, wood_type, paint_stages, sound_deadening_rating, source) VALUES (62, 37, 64.8, 72, 70, 62, 65, 58, 60, 'E90 platform — good chassis engineering for era. 50:50 weight distribution. MacPherson strut front, multi-link rear (Z-axle). High-quality steel for period. Panel gaps 4.5-5.5mm (good for 2000s). Aluminum hood on some models. Now 15+ years old — fatigue on rubber mounts, bushings. Rust on rear quarter panels and underbody in northern cars. Well-engineered but aging.', 'Good NVH for era, decent by modern standards. Hydraulic engine mounts standard on 6-cylinder. No acoustic glass standard (available on later LCI). N52 I6 smooth and refined. ZF 6HP well-isolated. Road noise on run-flat tires noticeable. Wind noise around mirrors at speed. Not as quiet as E60 5 Series of same era.', 'E90 interior functional but not luxurious. Dakota leather on 6-cylinder models (mid-grade). Leatherette on 4-cylinder. Hard plastics on lower door panels and center console. Aluminum or wood trim options. iDrive available (CIC on later models). Good ergonomics. Fit and finish above average for class. Orange peel on some interior plastics.', 'BMW paint mid-2000s: decent but not exceptional. Clear coat thin by modern standards. Some colors (Space Gray, Monaco Blue) hold up better. Stone chips expose steel on hood. Rear quarter rust near wheel arch on northern cars. Underbody surface rust common. Aluminum hood doesn''t rust but cosmetic corrosion on chips.', 'E90 electronics aging. iDrive CIC/NBT units can develop screen issues. Battery registration required. Window regulators fail. Door lock actuators fail. Final stage resistor (blower motor) fails. K-CAN bus issues cause intermittent warning lights. Electric water pump fails without warning. Better than E46 electronics but showing age now.', 'Dakota leather develops patina at 80-100K. Steering wheel glossy at 60K+. Hard plastic trim holds up but shows scratches. Soft-touch surfaces on door armrests can become sticky in hot climates. Dashboard material okay. Headliner sag possible at 15+ years. Overall: ages like a well-used German car — functional but showing.', 'E90 3 Series Q-score 64.8. Good 2000s build quality, now aging. N52 is the reliable heart. Interior materials mid-grade. Electronics aging is the real concern. Better than E46 in every dimension but below modern G20 standards.', 'shared', 'Munich (Germany) / Rosslyn (South Africa)', 'laser_welded', 5.0, 'hydraulic', 'standard', 'standard', 'real_wood', 3, 'average', 'sample');

-- car_id=41 | BMW 7 Series G11/G12 | N63TU2 4.4T 444hp
-- Q: 86*0.25 + 88*0.10 + 85*0.20 + 80*0.15 + 58*0.15 + 72*0.15 = 78.8
INSERT INTO build_quality (id, car_id, q_score, score_body_construction, score_nvh_isolation, score_interior_materials, score_paint_corrosion, score_electrical_aging, score_cosmetic_aging, body_construction_notes, nvh_isolation_notes, interior_materials_notes, paint_corrosion_notes, electrical_aging_notes, cosmetic_aging_notes, q_score_notes, platform_type, assembly_plant, weld_technology, panel_gap_mm, engine_mount_type, glass_type, leather_grade, wood_type, paint_stages, sound_deadening_rating, source) VALUES (63, 41, 78.8, 86, 88, 85, 80, 58, 72, 'Same CLAR flagship platform as 740i. Carbon core CFRP technology. Mixed high-strength steel, aluminum, carbon fiber. Excellent crash structure. Best panel gaps in BMW lineup at 3.5-4mm. V8 adds weight over front axle but body rigidity outstanding. Aluminum hood, doors, fenders. Carbon fiber B-pillar and roof rail core.', 'Same flagship NVH as 740i. N63 V8 slightly more present than B58 I6 but well-isolated. Hydraulic engine mounts standard. Acoustic laminated glass all around. Extensive firewall and underbody insulation. Air suspension standard. Near-silent at highway speeds. Wind noise well-managed. Tire noise the dominant source above 70mph.', 'Same premium interior as 740i. Nappa leather standard. Merino individual leather optional. Real wood trim abundant. Excellent fit and finish. Gesture control, touchscreen iDrive. Soft-close doors. Ambient lighting. Bowers and Wilkins optional. V8 model gets additional stitching and M Sport details standard. Above average for class.', 'Same BMW premium paint as 740i. Extra clear coat depth on Individual colors. Consistent application. No systemic issues. Well-protected structural steel. Aluminum panels cosmetic-only corrosion risk.', 'Same electronics complexity concerns as 740i. N63 adds engine management complexity — twin turbo control, cylinder deactivation, additional sensors. More modules = more failure points. Air suspension electronics. Driver assistance suite. Battery management for multiple systems. Software updates critical.', 'Same cosmetic aging as 740i. Nappa/Merino leather ages well. Real wood durable. Aluminum trim shows wear. Piano black surfaces scratch. Premium materials overall should age gracefully with proper care.', '750i G11 Q-score 78.8. Same excellent body construction and NVH as 740i. N63 V8 adds complexity and potential engine aging concerns not reflected in Q-score (that''s reliability). Build quality is flagship-level. Electronics complexity the main aging risk.', 'shared', 'Dingolfing (Germany)', 'mixed', 3.8, 'hydraulic', 'acoustic_laminated', 'nappa', 'real_wood', 5, 'excellent', 'sample');

-- car_id=50 | BMW X3 M40i G01 | B58 3.0T 355hp
-- Q: 78*0.25 + 75*0.10 + 75*0.20 + 78*0.15 + 65*0.15 + 68*0.15 = 73.7
INSERT INTO build_quality (id, car_id, q_score, score_body_construction, score_nvh_isolation, score_interior_materials, score_paint_corrosion, score_electrical_aging, score_cosmetic_aging, body_construction_notes, nvh_isolation_notes, interior_materials_notes, paint_corrosion_notes, electrical_aging_notes, cosmetic_aging_notes, q_score_notes, platform_type, assembly_plant, weld_technology, panel_gap_mm, engine_mount_type, glass_type, leather_grade, wood_type, paint_stages, sound_deadening_rating, source) VALUES (64, 50, 73.7, 78, 75, 75, 78, 65, 68, 'CLAR SUV platform shared with G20 3 Series and G30 5 Series. Mixed high-strength steel and aluminum. Aluminum hood and tailgate. Hot-stamped B-pillar. SUV body has good rigidity. Panel gaps 4-4.5mm. Good crash structure. Higher center of gravity than sedans but well-managed. Underbody protection adequate.', 'Good SUV NVH. B58 I6 smooth and quiet. Hydraulic engine mounts. Acoustic laminated windshield standard. Moderate firewall insulation. Road noise with SUV tire sizes. Some wind noise around mirror mounts at highway speeds. Better than F25 X3 predecessor. Run-flat tire harshness on rough surfaces. Competitive for premium compact SUV class.', 'M40i gets Vernasca leather (good upgrade over Sensatec base). Aluminum trim or optional wood. iDrive 7 with 10.25-inch screen. Good fit and finish. Soft-touch surfaces on upper panels. Harder plastics on lower door cards. Panoramic sunroof standard on M40i. Good ergonomics for SUV. Heated seats standard. Cooled seats available.', 'Modern BMW paint process. Multi-stage application. No systemic issues. Consistent color and clear coat. Aluminum panels don''t rust. Steel structure well-protected. Paint hardness average for German cars. Stone chips on front end cosmetic issue.', 'iDrive 7 generally stable. B58 electronics well-sorted. xDrive transfer case electronics. Panoramic sunroof electronics and drain management. Power tailgate electronics. Fewer modules than 5/7 Series. Better electronics trajectory than N-series era BMWs.', 'Vernasca leather aging well in initial reports. Panoramic sunroof mechanism can develop rattles. Interior trim materials durable. Less piano black than earlier models. Steering wheel gloss pattern at 60K+. Dashboard materials holding up. SUV utility means interior takes more abuse.', 'X3 M40i G01 Q-score 73.7. Solid premium SUV build quality. B58 powertrain a known quantity. Interior materials good but not 5 Series-level. NVH competitive for class. Electronics simpler than 5/7 Series. Good daily driver quality.', 'shared', 'Spartanburg (USA)', 'mixed', 4.2, 'hydraulic', 'acoustic_laminated', 'standard', 'real_wood', 4, 'above_average', 'sample');

-- car_id=51 | BMW X3 G01 M40i | B58 3.0T 355hp (duplicate of car_id=50)
-- Q: 78*0.25 + 75*0.10 + 75*0.20 + 78*0.15 + 65*0.15 + 68*0.15 = 73.7
INSERT INTO build_quality (id, car_id, q_score, score_body_construction, score_nvh_isolation, score_interior_materials, score_paint_corrosion, score_electrical_aging, score_cosmetic_aging, body_construction_notes, nvh_isolation_notes, interior_materials_notes, paint_corrosion_notes, electrical_aging_notes, cosmetic_aging_notes, q_score_notes, platform_type, assembly_plant, weld_technology, panel_gap_mm, engine_mount_type, glass_type, leather_grade, wood_type, paint_stages, sound_deadening_rating, source) VALUES (65, 51, 73.7, 78, 75, 75, 78, 65, 68, 'CLAR SUV platform, same construction as car_id=50. Mixed high-strength steel and aluminum. Aluminum hood and tailgate. Panel gaps 4-4.5mm. Good rigidity for SUV class.', 'Same NVH as car_id=50. B58 smooth, hydraulic mounts, acoustic windshield. Good SUV refinement.', 'Same M40i interior as car_id=50. Vernasca leather, good materials.', 'Same BMW paint process as car_id=50.', 'Same electronics as car_id=50.', 'Same cosmetic aging profile as car_id=50.', 'Duplicate X3 M40i entry (car_id=51). Same Q-score 73.7 as car_id=50.', 'shared', 'Spartanburg (USA)', 'mixed', 4.2, 'hydraulic', 'acoustic_laminated', 'standard', 'real_wood', 4, 'above_average', 'sample');

-- car_id=52 | BMW X5 G05 xDrive40i | B58 3.0T 335hp
-- Q: 82*0.25 + 80*0.10 + 82*0.20 + 78*0.15 + 62*0.15 + 70*0.15 = 76.4
INSERT INTO build_quality (id, car_id, q_score, score_body_construction, score_nvh_isolation, score_interior_materials, score_paint_corrosion, score_electrical_aging, score_cosmetic_aging, body_construction_notes, nvh_isolation_notes, interior_materials_notes, paint_corrosion_notes, electrical_aging_notes, cosmetic_aging_notes, q_score_notes, platform_type, assembly_plant, weld_technology, panel_gap_mm, engine_mount_type, glass_type, leather_grade, wood_type, paint_stages, sound_deadening_rating, source) VALUES (66, 52, 76.4, 82, 80, 82, 78, 62, 70, 'CLAR larger SUV platform. More substantial than X3. Mixed high-strength steel and aluminum. Aluminum hood, front fenders, doors. Larger body well-engineered. Panel gaps 3.8-4.2mm (tighter than X3). Good crash structure. Air suspension optional. Underbody well-protected. Higher build investment than X3 reflects price point.', 'Better NVH than X3 — larger body absorbs more. B58 smooth I6. Hydraulic mounts standard. Acoustic laminated windshield and available side glass. Extensive insulation. Air suspension (optional) excellent for isolation. Cabin very quiet at highway speeds. Better than G05 predecessor F15. Near-7-Series quiet at cruise.', 'Premium interior above X3 level. Vernasca or optional Nappa leather. Real wood trim extensive. iDrive 7 with large screen. Excellent fit and finish. Panoramic sky lounge roof option (LED-illuminated). Soft-touch surfaces throughout. Good storage. Heated and cooled seats available. Third row option on some builds.', 'Modern BMW premium paint. Same multi-stage process. Good clear coat depth. Consistent application. No systemic issues. Well-protected structure. Aluminum panels cosmetic-only corrosion. Paint quality appropriate for price point.', 'More complex than X3: air suspension management, panoramic roof electronics, more driver assistance modules, third row electronics (if equipped). iDrive 7 stable but more points of failure. B58 electronics well-sorted. Larger vehicle = more wiring harnesses and connectors.', 'Premium materials should age well. Vernasca/Nappa leather durable. Real wood trim ages gracefully. Panoramic roof mechanism potential rattle source. Interior takes family abuse — kids, cargo. Dashboard materials premium. Steering wheel typical BMW gloss pattern. Better aging trajectory than X3 due to higher-grade materials.', 'X5 xDrive40i G05 Q-score 76.4. Premium SUV build quality above X3 level. Better NVH, better interior materials, tighter panel gaps. B58 powertrain proven. Air suspension and electronics are aging concerns. Good choice in midsize luxury SUV class.', 'shared', 'Spartanburg (USA)', 'mixed', 4.0, 'hydraulic', 'acoustic_laminated', 'nappa', 'real_wood', 4, 'very_good', 'sample');

-- car_id=65 | BMW M5 E39 | S62 5.0L V8 NA 394hp
-- Q: 68*0.25 + 65*0.10 + 70*0.20 + 58*0.15 + 48*0.15 + 55*0.15 = 61.7
INSERT INTO build_quality (id, car_id, q_score, score_body_construction, score_nvh_isolation, score_interior_materials, score_paint_corrosion, score_electrical_aging, score_cosmetic_aging, body_construction_notes, nvh_isolation_notes, interior_materials_notes, paint_corrosion_notes, electrical_aging_notes, cosmetic_aging_notes, q_score_notes, platform_type, assembly_plant, weld_technology, panel_gap_mm, engine_mount_type, glass_type, leather_grade, wood_type, paint_stages, sound_deadening_rating, source) VALUES (67, 65, 61.7, 68, 65, 70, 58, 48, 55, 'E39 platform — legendary chassis rigidity for era. All-steel body (no aluminum panels on M5). MacPherson strut front, multi-link rear. Excellent 50:50 weight distribution. Panel gaps 4.5-5.5mm (good for 1998-2003). Strong weld quality for period. Well-documented crash structure. Now 20+ years old — rust on rear quarter panels, underbody, jack points common in northern cars.', 'Good NVH for era. Hydraulic engine mounts. Moderate firewall insulation. S62 V8 has character — audible but refined at cruise, aggressive under load. No acoustic glass. Getrag 6-speed manual well-isolated. Wind noise around mirrors at highway speed. Better than E46 M3 in refinement, not E39 540i-level quiet due to stiffer M suspension.', 'Often called the best M5 interior. Nappa leather sport seats (electric with memory). Real wood trim — warm, traditional BMW design. Aluminum or wood trim options. Good fit and finish for era. Soft-touch upper door panels. Hard plastics lower. Manual-specific: leather-wrapped shift knob, boot. Analog gauges excellent. Interior design has aged well aesthetically.', 'BMW paint late 1990s/early 2000s: adequate but not outstanding. Clear coat thin by modern standards. Some colors (Le Mans Blue, Carbon Black) prone to clear coat failure at 15+ years. Stone chips expose steel. Rear quarter rust near wheel arch common. Underbody surface rust. Silver and white hold up best.', 'E39 electronics aging poorly now. Instrument cluster pixels fail (common E39). Window regulators fail. Final stage resistor (hedgehog) causes blower issues. Mirror motors fail. Seat memory modules fail. S62-specific: MAF sensors, VANOS solenoids, thermostat electronic failure trigger warning lights. K-bus issues. Battery drain from aging modules.', 'Nappa leather seats age with character — cracking on bolsters at 80-100K if not conditioned. Steering wheel leather thin and glossy at 50K+. Wood trim holds up well. Dashboard material prone to cracking in sun (common E39). Door panel leather peels at edges. Headliner sag at 15+ years. Center console armrest vinyl cracks. Overall: better than E46 but showing age.', 'E39 M5 Q-score 61.7. Legendary car but 20+ years of aging shows. Interior design timeless but materials have degraded. Electronics are the weak point. Chassis engineering outstanding for era. The "best M5" reputation is earned through driving dynamics, not build quality.', 'bespoke', 'Dingolfing (Germany)', 'laser_welded', 5.0, 'hydraulic', 'standard', 'nappa', 'real_wood', 3, 'average', 'sample');

-- car_id=106 | BMW M3 E30 | S14 2.3L I4 NA 192hp
-- Q: 45*0.25 + 35*0.10 + 45*0.20 + 40*0.15 + 60*0.15 + 42*0.15 = 45.0
INSERT INTO build_quality (id, car_id, q_score, score_body_construction, score_nvh_isolation, score_interior_materials, score_paint_corrosion, score_electrical_aging, score_cosmetic_aging, body_construction_notes, nvh_isolation_notes, interior_materials_notes, paint_corrosion_notes, electrical_aging_notes, cosmetic_aging_notes, q_score_notes, platform_type, assembly_plant, weld_technology, panel_gap_mm, engine_mount_type, glass_type, leather_grade, wood_type, paint_stages, sound_deadening_rating, source) VALUES (68, 106, 45.0, 45, 35, 45, 40, 60, 42, 'E30 platform — 1980s steel body, lightweight. Box flared fenders for Group A homologation. MacPherson strut front, semi-trailing arm rear. Panel gaps 5-7mm (normal for 1980s). Good chassis rigidity for period. Now 35+ years old — rust is the primary enemy. Rear quarter panels, floor pan, jack points, front fender lips, shock towers. Nearly every example has rust somewhere. Weld quality era-appropriate.', '1980s NVH — minimal by any modern standard. Solid rubber mounts. No acoustic glass. No sound deadening to speak of. S14 mechanically noisy — valve train, intake, exhaust all audible. Wind noise around window seals at speed. Road noise with 15-inch tires (less than modern 19s actually). You feel every road seam. Charming but not refined. Purposeful.', '1980s BMW sports interior. Sport seats well-bolstered for era, cloth or leather. Leatherette on base models. Hard plastics throughout. Simple analog gauges. No iDrive. Basic HVAC controls. Functional and honest. Materials quality acceptable for 1986-1991 but poor by any modern standard. headliner sag common. Seat bolster wear on driver''s side.', '1980s BMW paint — thin, single-stage on some colors. Clear coat failure nearly universal on original paint cars. Many examples resprayed. Stone chips everywhere on driven examples. Exposed steel rusts quickly. Paint correction community documents extensive E30 paint issues. Original paint in good condition adds significant value.', 'Simple 1980s Bosch Motronic electronics — actually aging well because there''s less to fail. Analog gauges. Simple wiring harnesses. No modules, no bus systems. Basic relay-based electronics. Capacitor aging in ECU possible at 30+ years. OBD-I diagnostics. The simplicity is a feature — easy to diagnose and repair.', '35+ year old materials. Seat leather/vinyl cracked on bolsters. Dashboard cracked (UV exposure). Door panels faded. Steering wheel worn thin. Carpet worn. Headliner sag. Chrome trim pitted. Rubber seals hardened and cracked. Windshield pitted. Every cosmetic element shows age on unrestored cars. Patina adds character but not quality.', 'E30 M3 Q-score 45.0. A 35+ year old homologation special — build quality reflects 1980s standards plus decades of aging. Rust is the dominant factor. NVH is purposeful race-car minimalism. Electronics are simple and actually reliable. Interior is spartan. Scores reflect a classic, not a modern car.', 'bespoke', 'Munich (Germany) / Regensburg (Germany)', 'spot_welded', 6.0, 'solid_rubber', 'standard', 'standard', 'none', 2, 'minimal', 'sample');

-- car_id=120 | BMW M5 F90 Competition | S63 4.4L V8 twin-turbo 617hp
-- Q: 88*0.25 + 78*0.10 + 85*0.20 + 82*0.15 + 65*0.15 + 72*0.15 = 79.6
INSERT INTO build_quality (id, car_id, q_score, score_body_construction, score_nvh_isolation, score_interior_materials, score_paint_corrosion, score_electrical_aging, score_cosmetic_aging, body_construction_notes, nvh_isolation_notes, interior_materials_notes, paint_corrosion_notes, electrical_aging_notes, cosmetic_aging_notes, q_score_notes, platform_type, assembly_plant, weld_technology, panel_gap_mm, engine_mount_type, glass_type, leather_grade, wood_type, paint_stages, sound_deadening_rating, source) VALUES (69, 120, 79.6, 88, 78, 85, 82, 65, 72, 'CLAR F90 platform — the largest, most rigid application. Mixed high-strength steel, aluminum, carbon fiber options (CFRP roof on Competition). Aluminum hood, front fenders, doors. Hot-stamped structural members. Panel gaps 3.5-4mm (excellent). M-specific structural bracing. Excellent crash structure. Body rigidity outstanding. Production quality consistently high — Dingolfing flagship line.', 'Impressive NVH for 617hp. Adaptive engine mounts switch between comfort and sport. Acoustic laminated glass. Extensive firewall insulation. S63 V8 well-isolated in comfort mode, muscular in sport. Active sound design supplements exhaust note. Wind noise well-managed. Tire noise from wide performance rubber. Better NVH than F10 M5. Not 7 Series quiet but impressive for an M car.', 'M Competition interior: Merino leather standard, extended. Carbon fiber trim standard on Competition. Alcantara headliner. M Sport seats or optional M carbon bucket seats. iDrive 7 with M-specific screens. Excellent fit and finish. Soft-close doors. Ambient lighting. Harman Kardon or optional Bowers and Wilkins. M-specific steering wheel with M1/M2 buttons. Premium throughout.', 'BMW premium paint on M cars. Extra quality control. Multi-layer clear coat. Competition-specific colors available. Consistent application. No systemic issues. Paint depth above average. Individual paint options have additional clear coat. Well-protected structure.', 'M-specific electronics complex: M drive management, adaptive damping, active M differential, M xDrive, active steering, head-up display, driving assistance professional. Multiple ECUs. Software-dependent. Too new for definitive long-term data but more complex than standard 5 Series. OTA updates add software risk.', 'Merino leather should age well — premium grade. Alcantara headliner durable. Carbon fiber trim doesn''t degrade. M Sport seats see more aggressive use. Steering wheel M-specific thicker leather. Interior materials premium throughout. Too new for long-term aging data but materials quality suggests good trajectory. Limited-edition status means owners care for them.', 'F90 M5 Competition Q-score 79.6. Modern M car flagship build quality. Best panel gaps and body rigidity in M lineup. Premium interior with Merino leather throughout. NVH impressive for the power level. Electronics complexity is the aging concern. Carbon fiber options add visual and structural quality.', 'shared', 'Dingolfing (Germany)', 'mixed', 3.7, 'adaptive_hydraulic', 'acoustic_laminated', 'merino', 'carbon_fiber', 5, 'excellent', 'sample');

-- car_id=123 | BMW iX xDrive50 first gen | 516hp electric
-- Q: 85*0.25 + 90*0.10 + 88*0.20 + 82*0.15 + 55*0.15 + 75*0.15 = 79.7
INSERT INTO build_quality (id, car_id, q_score, score_body_construction, score_nvh_isolation, score_interior_materials, score_paint_corrosion, score_electrical_aging, score_cosmetic_aging, body_construction_notes, nvh_isolation_notes, interior_materials_notes, paint_corrosion_notes, electrical_aging_notes, cosmetic_aging_notes, q_score_notes, platform_type, assembly_plant, weld_technology, panel_gap_mm, engine_mount_type, glass_type, leather_grade, wood_type, paint_stages, sound_deadening_rating, source) VALUES (70, 123, 79.7, 85, 90, 88, 82, 55, 75, 'CLAR-based EV platform with battery integration. CFRP (carbon fiber reinforced polymer) cell and roof cage for battery protection and body rigidity. Mixed high-strength steel, aluminum, carbon fiber. Aluminum body panels. Excellent crash structure with battery-specific crumple zones. Panel gaps 3.5-4mm. Flat floor from skateboard architecture. EV-specific structural considerations well-engineered.', 'Outstanding NVH — EV advantage. No engine vibration or noise. Near-silent at low speeds. Wind noise very well-managed with frameless doors (impressive engineering). Extensive sound deadening. Acoustic laminated glass all around. Road noise the only significant source, and it''s well-controlled. Cabin extremely quiet at highway speeds. Among quietest SUVs regardless of powertrain.', 'Premium iX interior with sustainable materials focus. Olive-leaf tanned leather option. Optional lounge seats. Crystal iDrive controller. Dual curved displays. Shy Tech — hidden speakers, minimalist design. Real wood options. Excellent fit and finish. Soft-touch throughout. Panoramic glass roof with electrochromic dimming. Interior design forward-looking. Materials quality at or near BMW best.', 'BMW premium paint on EV flagship. Extra quality control. Multi-layer application. No systemic issues. Consistent clear coat. EV-specific considerations: no heat from engine bay, different thermal cycling on paint. Too early for long-term paint data but initial quality high.', 'Early iX (2022-2023) recall-heavy per Consumer Reports. Multiple recalls: pedestrian sound generator, CID safety info, battery modules, steering system. Software-dependent vehicle. OTA updates critical but can introduce bugs. Connected Drive services can fail (WiFi/Internet issues reported). Many electronic modules. First-generation EV electronics risk.', 'Sustainable materials concept should age well. Olive leaf-tanned leather reportedly durable. Crystal controls won''t degrade. Curved displays should hold up (too new for long-term data). Electrochromic roof mechanism unknown longevity. Interior design is distinctive and well-assembled. Premium materials throughout.', 'iX xDrive50 Q-score 79.7. Excellent build quality typical of BMW EV flagship. Outstanding NVH from EV powertrain. Premium sustainable interior. Electronics aging the main concern — early models recall-heavy. Body construction excellent with CFRP battery cage. Competitive with Mercedes EQS SUV.', 'ev_skateboard', 'Dingolfing (Germany)', 'mixed', 3.8, 'fixed', 'acoustic_laminated', 'premium_sustainable', 'real_wood', 5, 'outstanding', 'sample');
